// LookupIP looks up endpoint by IP address
func (mgr *endpointManager) LookupIP(ip netip.Addr) (ep *endpoint.Endpoint) {
	ipStr := ip.Unmap().String()
	mgr.mutex.RLock()
	if ip.Is4() {
		ep = mgr.lookupIPv4(ipStr)
	} else {
		ep = mgr.lookupIPv6(ipStr)
